const TOPIC = msg.topic;
const statuses = ['NEW', 'RELEASED', 'RELEASED', 'RELEASED']; // More RELEASED for wave testing
const customers = ['CUSTOMER-A', 'CUSTOMER-B', 'HENKEL-SUZHOU', 'HENKEL-BEIJING'];
const materials = ['GLUE-500', 'SEALANT-X', 'ADHESIVE-PRO', 'COATING-UV'];

let dnDB = global.get('outbound_dn_db') || { items: [] };

// Generate 3-5 new orders
let count = Math.floor(Math.random() * 3) + 3;
for (let i = 0; i < count; i++) {
    let status = statuses[Math.floor(Math.random() * statuses.length)];
    let dnNo = 'DN-' + new Date().toISOString().slice(0,10).replace(/-/g,'') + '-' + String(dnDB.items.length + 1).padStart(3, '0');

    let order = {
        dn_no: dnNo,
        id: dnNo,
        type: Math.random() > 0.3 ? 'SALES_ORDER' : 'TRANSFER_OUT',
        status: status,
        customer: customers[Math.floor(Math.random() * customers.length)],
        destination: 'Shanghai-' + (Math.floor(Math.random() * 3) + 1),
        warehouse: 'WH-SHANGHAI',
        requested_date: new Date(Date.now() + 86400000 * Math.floor(Math.random() * 7)).toISOString().split('T')[0],
        wave_id: null,
        lines: [
            { code: materials[Math.floor(Math.random() * materials.length)], qty: Math.floor(Math.random() * 100) + 10, qty_allocated: 0 },
            { code: materials[Math.floor(Math.random() * materials.length)], qty: Math.floor(Math.random() * 50) + 5, qty_allocated: 0 }
        ],
        created_at: Date.now(),
        priority: Math.random() > 0.7 ? 'HIGH' : 'NORMAL'
    };
    dnDB.items.unshift(order);
}

// Keep only last 30
if (dnDB.items.length > 30) dnDB.items = dnDB.items.slice(0, 30);
global.set('outbound_dn_db', dnDB);

msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: dnDB }]
};

node.warn('Generated ' + count + ' orders. Total: ' + dnDB.items.length);
return msg;

const TOPIC_WAVE = msg.topic;
const TOPIC_DN = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
const carriers = ['SF-EXPRESS', 'DHL', 'SINOTRANS', 'JD-LOGISTICS'];
const routes = ['Shanghai North', 'Shanghai South', 'Suzhou Route', 'Hangzhou Line'];

let waveDB = global.get('wave_db') || { items: [] };
let dnDB = global.get('outbound_dn_db') || { items: [] };

// Find RELEASED DNs without wave assignment
let availableDNs = dnDB.items.filter(o => 
    o.status === 'RELEASED' && !o.wave_id
);

if (availableDNs.length === 0) {
    node.warn('No RELEASED DNs available. Generate DNs first!');
    return null;
}

// Generate wave ID
let datePart = new Date().toISOString().slice(0, 10).replace(/-/g, '');
let key = 'wave_seq_' + datePart;
let seq = (global.get(key) || 0) + 1;
global.set(key, seq);

// Pick 2-4 DNs for this wave
let pickCount = Math.min(Math.floor(Math.random() * 3) + 2, availableDNs.length);
let selectedDNs = availableDNs.slice(0, pickCount);

// Calculate line count from selected DNs
let lineCount = selectedDNs.reduce((sum, dn) => sum + (dn.lines || []).length, 0);

// Create wave with REAL delivery_ids
let wave = {
    wave_id: 'WAVE-' + datePart + '-' + String(seq).padStart(3, '0'),
    status: 'PLANNED',
    ship_date: new Date(Date.now() + 86400000 * Math.floor(Math.random() * 3)).toISOString().split('T')[0],
    carrier: carriers[Math.floor(Math.random() * carriers.length)],
    route: routes[Math.floor(Math.random() * routes.length)],
    pick_method: Math.random() > 0.5 ? 'BATCH' : 'DISCRETE',
    delivery_ids: selectedDNs.map(d => d.dn_no),
    delivery_count: selectedDNs.length,
    line_count: lineCount,
    picks_completed: 0,
    picks_total: 0,
    created_at: Date.now()
};

// Update DN status to WAVE_ASSIGNED
selectedDNs.forEach(dn => {
    dn.wave_id = wave.wave_id;
    dn.status = 'WAVE_ASSIGNED';
});

waveDB.items.unshift(wave);

// Keep only last 20 waves
if (waveDB.items.length > 20) waveDB.items = waveDB.items.slice(0, 20);

global.set('wave_db', waveDB);
global.set('outbound_dn_db', dnDB);

node.warn('Created wave ' + wave.wave_id + ' with ' + selectedDNs.length + ' orders: ' + wave.delivery_ids.join(', '));

// Return both wave and DN updates
let msgWave = {
    topic: TOPIC_WAVE,
    payload: { version: '1.0', topics: [{ path: TOPIC_WAVE, type: 'state', value: waveDB }] }
};
let msgDN = {
    topic: TOPIC_DN,
    payload: { version: '1.0', topics: [{ path: TOPIC_DN, type: 'state', value: dnDB }] }
};

return [[msgWave, msgDN]];

const TOPIC = msg.topic;
const locations = ['A-01-01', 'A-02-03', 'B-01-02', 'B-03-01', 'C-02-04'];

let dnDB = global.get('outbound_dn_db') || { items: [] };
let waveDB = global.get('wave_db') || { items: [] };
let taskDB = global.get('outbound_task_db') || { items: [] };

// Find DNs that are ALLOCATED or IN_PROGRESS waves
let allocatedDNs = dnDB.items.filter(o => 
    o.status === 'ALLOCATED' || o.status === 'PICKING'
);

if (allocatedDNs.length === 0) {
    // Fallback: create sample tasks
    let count = Math.floor(Math.random() * 5) + 3;
    for (let i = 0; i < count; i++) {
        taskDB.items.unshift({
            task_id: 'PICK-' + Date.now() + '-' + i,
            status: 'PENDING',
            material_code: ['GLUE-500', 'SEALANT-X', 'ADHESIVE-PRO'][Math.floor(Math.random() * 3)],
            material_name: 'Material ' + (i + 1),
            batch: 'B2026' + String(Math.floor(Math.random() * 1000)).padStart(3, '0'),
            from_location: locations[Math.floor(Math.random() * locations.length)],
            to_location: 'STAGE-0' + (Math.floor(Math.random() * 3) + 1),
            qty: Math.floor(Math.random() * 50) + 10,
            uom: 'EA',
            wave_id: 'WAVE-SAMPLE',
            dn_no: 'DN-SAMPLE-' + i,
            priority: Math.random() > 0.7 ? 'HIGH' : 'NORMAL',
            created_at: Date.now()
        });
    }
} else {
    // Create tasks from real allocated DNs
    allocatedDNs.forEach(dn => {
        (dn.lines || []).forEach((line, idx) => {
            // Check if task already exists
            let existingTask = taskDB.items.find(t => t.dn_no === dn.dn_no && t.material_code === line.code);
            if (!existingTask) {
                taskDB.items.unshift({
                    task_id: 'PICK-' + Date.now() + '-' + Math.floor(Math.random() * 1000),
                    status: 'PENDING',
                    material_code: line.code,
                    material_name: line.code,
                    batch: 'B2026' + String(Math.floor(Math.random() * 1000)).padStart(3, '0'),
                    from_location: locations[Math.floor(Math.random() * locations.length)],
                    to_location: 'STAGE-01',
                    qty: line.qty,
                    uom: 'EA',
                    wave_id: dn.wave_id || 'NO-WAVE',
                    dn_no: dn.dn_no,
                    priority: dn.priority || 'NORMAL',
                    created_at: Date.now()
                });
            }
        });
        dn.status = 'PICKING';
    });
    global.set('outbound_dn_db', dnDB);
}

if (taskDB.items.length > 50) taskDB.items = taskDB.items.slice(0, 50);
global.set('outbound_task_db', taskDB);

msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: { tasks: taskDB.items } }]
};

node.warn('Generated ' + taskDB.items.length + ' pick tasks');
return msg;

const TOPIC = msg.topic;
const areas = ['STAGE-01', 'STAGE-02', 'STAGE-03', 'STAGE-04'];
const materials = ['GLUE-500', 'SEALANT-X', 'ADHESIVE-PRO'];

let stagingAreas = areas.map(areaId => {
    let itemCount = Math.floor(Math.random() * 4);
    let items = [];
    for (let i = 0; i < itemCount; i++) {
        items.push({
            hu_id: 'HU-' + Math.floor(Math.random() * 10000),
            material_code: materials[Math.floor(Math.random() * materials.length)],
            qty: Math.floor(Math.random() * 100) + 10,
            dn_no: 'DN-' + Math.floor(Math.random() * 10000),
            wave_id: 'WAVE-' + Math.floor(Math.random() * 100),
            staged_at: Date.now() - Math.floor(Math.random() * 3600000)
        });
    }
    return {
        area_id: areaId,
        capacity: 20,
        used: items.length,
        items: items
    };
});

global.set('staging_areas', { areas: stagingAreas });

msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: { areas: stagingAreas } }]
};

return msg;

const TOPIC = msg.topic;
const dockStatuses = ['AVAILABLE', 'WAITING', 'LOADING', 'COMPLETED'];
const carriers = ['SF-EXPRESS', 'DHL', 'SINOTRANS', 'JD-LOGISTICS'];

let docks = [];
for (let i = 1; i <= 6; i++) {
    let status = dockStatuses[Math.floor(Math.random() * dockStatuses.length)];
    docks.push({
        dock_id: 'DOCK-0' + i,
        status: status,
        carrier: status !== 'AVAILABLE' ? carriers[Math.floor(Math.random() * carriers.length)] : null,
        vehicle: status !== 'AVAILABLE' ? '沪A' + String(Math.floor(Math.random() * 90000) + 10000) : null,
        shipments: status === 'LOADING' || status === 'WAITING' ? Math.floor(Math.random() * 3) + 1 : 0,
        total_items: status === 'LOADING' ? Math.floor(Math.random() * 50) + 10 : 0,
        loaded_items: status === 'LOADING' ? Math.floor(Math.random() * 30) : 0,
        arrival_time: status !== 'AVAILABLE' ? Date.now() - Math.floor(Math.random() * 7200000) : null
    });
}

global.set('loading_docks', { docks: docks });

msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: { docks: docks } }]
};

return msg;

// Clear all global context
global.set('outbound_dn_db', { items: [] });
global.set('wave_db', { items: [] });
global.set('outbound_task_db', { items: [] });
global.set('shipment_list', { items: [] });
global.set('staging_areas', { areas: [] });
global.set('loading_docks', { docks: [] });

// Reset sequence counters
let today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
global.set('wave_seq_' + today, 0);

node.warn('All outbound data cleared!');

// Publish empty states
let topics = [
    'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB',
    'Henkelv2/Shanghai/Logistics/Outbound/State/Wave_List',
    'Henkelv2/Shanghai/Logistics/Outbound/State/Picking_Queue',
    'Henkelv2/Shanghai/Logistics/Outbound/State/Staging_Area',
    'Henkelv2/Shanghai/Logistics/Outbound/State/Loading_Docks',
    'Henkelv2/Shanghai/Logistics/Outbound/State/Shipment_List'
];

let messages = topics.map(t => ({
    topic: t,
    payload: { version: '1.0', topics: [{ path: t, type: 'state', value: { items: [] } }] }
}));

return [messages];

const TOPIC = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
let action = msg.payload;

let dnDB = global.get('outbound_dn_db') || { items: [] };

// Generate DN number
let datePart = new Date().toISOString().slice(0,10).replace(/-/g,'');
let dnNo = 'DN-' + datePart + '-' + String(dnDB.items.length + 1).padStart(3, '0');

let newOrder = {
    dn_no: dnNo,
    id: dnNo,
    type: action.type || 'SALES_ORDER',
    status: 'NEW',
    customer: action.customer || action.destination || 'Unknown',
