node.warn('Created order: ' + dnNo);
return msg;

const TOPIC = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
let action = msg.payload;

let dnDB = global.get('outbound_dn_db') || { items: [] };
let order = dnDB.items.find(o => o.dn_no === action.dn_no || o.id === action.dn_no);

if (!order) {
    node.warn('Hold Error: Order not found ' + action.dn_no);
    return null;
}

// Can only hold orders not yet in execution
const canHold = ['NEW', 'RELEASED', 'WAVE_ASSIGNED', 'APPROVED'].includes(order.status);
if (!canHold) {
    node.warn('Hold Error: Cannot hold order in status ' + order.status);
    return null;
}

// Store previous status and hold
order.previous_status = order.status;
order.status = 'ON_HOLD';
order.hold_reason = action.reason || 'Manual hold';
order.hold_at = Date.now();
order.hold_by = action.operator || 'System';

// If in a wave, remove from wave
if (order.wave_id) {
    let waveDB = global.get('wave_db') || { items: [] };
    let wave = waveDB.items.find(w => w.wave_id === order.wave_id);
    if (wave && wave.status === 'PLANNED') {
        wave.delivery_ids = wave.delivery_ids.filter(id => id !== order.dn_no);
        wave.delivery_count = wave.delivery_ids.length;
        global.set('wave_db', waveDB);
    }
    order.previous_wave_id = order.wave_id;
    order.wave_id = null;
}

global.set('outbound_dn_db', dnDB);

msg.topic = TOPIC;
msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: dnDB }]
};

node.warn('Order ' + action.dn_no + ' put on hold');
return msg;

const TOPIC = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
let action = msg.payload;

let dnDB = global.get('outbound_dn_db') || { items: [] };
let order = dnDB.items.find(o => o.dn_no === action.dn_no || o.id === action.dn_no);

if (!order) {
    node.warn('Release Hold Error: Order not found');
    return null;
}

if (order.status !== 'ON_HOLD') {
    node.warn('Release Hold Error: Order not on hold');
    return null;
}

// Restore previous status
order.status = order.previous_status || 'RELEASED';
delete order.previous_status;
delete order.hold_reason;
delete order.hold_at;
delete order.hold_by;
order.released_hold_at = Date.now();

global.set('outbound_dn_db', dnDB);

msg.topic = TOPIC;
msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: dnDB }]
};

node.warn('Order ' + action.dn_no + ' released from hold');
return msg;

const TOPIC = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
let action = msg.payload;

let dnDB = global.get('outbound_dn_db') || { items: [] };
let order = dnDB.items.find(o => o.dn_no === action.dn_no || o.id === action.dn_no);

if (!order) {
    node.warn('Review Error: Order not found');
    return null;
}

if (action.action === 'APPROVE') {
    order.status = 'RELEASED';
    order.approved_by = action.operator || 'System';
    order.approved_at = Date.now();
} else if (action.action === 'REJECT') {
    order.status = 'REJECTED';
    order.reject_reason = action.reason || 'No reason';
    order.rejected_by = action.operator || 'System';
    order.rejected_at = Date.now();
}

global.set('outbound_dn_db', dnDB);

msg.topic = TOPIC;
msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: dnDB }]
};

return msg;

