const TOPIC_WAVE = 'Henkelv2/Shanghai/Logistics/Outbound/State/Wave_List';
const TOPIC_DN = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
let action = msg.payload;

let waveDB = global.get('wave_db') || { items: [] };
let dnDB = global.get('outbound_dn_db') || { items: [] };

// Find wave
let wave = waveDB.items.find(w => w.wave_id === action.wave_id);
if (!wave) {
    node.warn('Add to Wave Error: Wave not found');
    return null;
}

if (wave.status !== 'PLANNED') {
    node.warn('Add to Wave Error: Wave not in PLANNED status');
    return null;
}

// Find order
let order = dnDB.items.find(o => o.dn_no === action.dn_no || o.id === action.dn_no);
if (!order) {
    node.warn('Add to Wave Error: Order not found');
    return null;
}

// Add order to wave
if (!wave.delivery_ids.includes(order.dn_no)) {
    wave.delivery_ids.push(order.dn_no);
    wave.delivery_count = wave.delivery_ids.length;
    wave.line_count += (order.lines || []).length;
}

// Update order
order.wave_id = wave.wave_id;
order.status = 'WAVE_ASSIGNED';

global.set('wave_db', waveDB);
global.set('outbound_dn_db', dnDB);

let msgWave = {
    topic: TOPIC_WAVE,
    payload: { version: '1.0', topics: [{ path: TOPIC_WAVE, type: 'state', value: waveDB }] }
};
let msgDN = {
    topic: TOPIC_DN,
    payload: { version: '1.0', topics: [{ path: TOPIC_DN, type: 'state', value: dnDB }] }
};

node.warn('Added ' + order.dn_no + ' to ' + wave.wave_id);
return [[msgWave, msgDN]];

const TOPIC_WAVE = 'Henkelv2/Shanghai/Logistics/Outbound/State/Wave_List';
const TOPIC_DN = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
let action = msg.payload;

let waveDB = global.get('wave_db') || { items: [] };
let dnDB = global.get('outbound_dn_db') || { items: [] };

let order = dnDB.items.find(o => o.dn_no === action.dn_no || o.id === action.dn_no);
if (!order || !order.wave_id) {
    node.warn('Remove from Wave Error: Order not found or not in wave');
    return null;
}

let wave = waveDB.items.find(w => w.wave_id === order.wave_id);
if (wave) {
    if (wave.status !== 'PLANNED') {
        node.warn('Remove from Wave Error: Cannot modify wave in status ' + wave.status);
        return null;
    }
    wave.delivery_ids = wave.delivery_ids.filter(id => id !== order.dn_no);
    wave.delivery_count = wave.delivery_ids.length;
    wave.line_count -= (order.lines || []).length;
}

order.wave_id = null;
order.status = 'RELEASED';

global.set('wave_db', waveDB);
global.set('outbound_dn_db', dnDB);

let msgWave = {
    topic: TOPIC_WAVE,
    payload: { version: '1.0', topics: [{ path: TOPIC_WAVE, type: 'state', value: waveDB }] }
};
let msgDN = {
    topic: TOPIC_DN,
    payload: { version: '1.0', topics: [{ path: TOPIC_DN, type: 'state', value: dnDB }] }
};

return [[msgWave, msgDN]];

const TOPIC_WAVE = 'Henkelv2/Shanghai/Logistics/Outbound/State/Wave_List';
const TOPIC_DN = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
const TOPIC_TASKS = 'Henkelv2/Shanghai/Logistics/Outbound/State/Picking_Queue';
let action = msg.payload;

let waveDB = global.get('wave_db') || { items: [] };
let dnDB = global.get('outbound_dn_db') || { items: [] };
let taskDB = global.get('outbound_task_db') || { items: [] };

let wave = waveDB.items.find(w => w.wave_id === action.wave_id);
if (!wave) {
    node.warn('Release Wave Error: Wave not found ' + action.wave_id);
    return null;
}

if (wave.status !== 'PLANNED') {
    node.warn('Release Wave Error: Wave not in PLANNED status');
    return null;
}

if (wave.delivery_ids.length === 0) {
    node.warn('Release Wave Error: Wave has no orders');
    return null;
}

// Update wave status
wave.status = 'RELEASED';
wave.released_at = Date.now();
wave.released_by = action.operator || 'System';

let totalPicks = 0;
const locations = ['A-01-01', 'A-02-03', 'B-01-02', 'B-03-01', 'C-02-04'];

// Process each delivery in the wave
wave.delivery_ids.forEach(dnId => {
    let order = dnDB.items.find(o => o.dn_no === dnId);
    if (!order) return;

    order.status = 'ALLOCATED';
    order.allocated_at = Date.now();

    // Create pick tasks for each line
    (order.lines || []).forEach((line, idx) => {
        let newTask = {
            task_id: 'PICK-' + Date.now() + '-' + Math.floor(Math.random() * 1000),
            wave_id: wave.wave_id,
            dn_no: order.dn_no,
            material_code: line.code,
            material_name: line.code,
            batch: 'B2026' + String(Math.floor(Math.random() * 1000)).padStart(3, '0'),
            qty: line.qty,
            from_location: locations[Math.floor(Math.random() * locations.length)],
            to_location: 'STAGE-01',
            status: 'PENDING',
            priority: order.priority || 'NORMAL',
            created_at: Date.now()
        };
        taskDB.items.unshift(newTask);
        totalPicks++;

        line.qty_allocated = line.qty;
    });
});

wave.picks_total = totalPicks;
wave.status = 'IN_PROGRESS';

global.set('wave_db', waveDB);
global.set('outbound_dn_db', dnDB);
global.set('outbound_task_db', taskDB);

let msgWave = {
    topic: TOPIC_WAVE,
    payload: { version: '1.0', topics: [{ path: TOPIC_WAVE, type: 'state', value: waveDB }] }
};
let msgDN = {
    topic: TOPIC_DN,
    payload: { version: '1.0', topics: [{ path: TOPIC_DN, type: 'state', value: dnDB }] }
};
let msgTasks = {
    topic: TOPIC_TASKS,
    payload: { version: '1.0', topics: [{ path: TOPIC_TASKS, type: 'state', value: { tasks: taskDB.items } }] }
};

node.warn('Released wave ' + wave.wave_id + ' with ' + totalPicks + ' pick tasks');
return [[msgWave, msgDN, msgTasks]];

const TOPIC_WAVE = 'Henkelv2/Shanghai/Logistics/Outbound/State/Wave_List';
const TOPIC_DN = 'Henkelv2/Shanghai/Logistics/Costing/State/DN_Workflow_DB';
let action = msg.payload;

let waveDB = global.get('wave_db') || { items: [] };
let dnDB = global.get('outbound_dn_db') || { items: [] };

let wave = waveDB.items.find(w => w.wave_id === action.wave_id);
if (!wave) {
    node.warn('Delete Wave: Wave not found');
    return null;
}

if (wave.status !== 'PLANNED' && wave.status !== 'RELEASED') {
    node.warn('Delete Wave: Cannot delete wave in status ' + wave.status);
    return null;
}

// Unassign orders from this wave
(wave.delivery_ids || []).forEach(dnId => {
    let order = dnDB.items.find(o => o.dn_no === dnId);
    if (order) {
        order.wave_id = null;
        order.status = 'RELEASED';
    }
});

// Remove wave
waveDB.items = waveDB.items.filter(w => w.wave_id !== action.wave_id);

global.set('wave_db', waveDB);
global.set('outbound_dn_db', dnDB);

let msgWave = {
    topic: TOPIC_WAVE,
    payload: { version: '1.0', topics: [{ path: TOPIC_WAVE, type: 'state', value: waveDB }] }
};
let msgDN = {
    topic: TOPIC_DN,
    payload: { version: '1.0', topics: [{ path: TOPIC_DN, type: 'state', value: dnDB }] }
};

node.warn('Deleted wave ' + action.wave_id);
return [[msgWave, msgDN]];

const TOPIC = 'Henkelv2/Shanghai/Logistics/Outbound/State/Picking_Queue';
let action = msg.payload;

let taskDB = global.get('outbound_task_db') || { items: [] };
let waveDB = global.get('wave_db') || { items: [] };

let task = taskDB.items.find(t => t.task_id === action.task_id);
if (!task) {
    node.warn('Confirm Pick: Task not found');
    return null;
}

task.status = 'COMPLETED';
task.completed_at = Date.now();
task.picked_qty = action.picked_qty || action.qty_picked || task.qty;
task.operator = action.operator || 'System';

// Update wave progress
let wave = waveDB.items.find(w => w.wave_id === task.wave_id);
if (wave) {
    wave.picks_completed = (wave.picks_completed || 0) + 1;
    if (wave.picks_completed >= wave.picks_total) {
        wave.status = 'COMPLETED';
        wave.completed_at = Date.now();
    }
    global.set('wave_db', waveDB);
}

global.set('outbound_task_db', taskDB);

msg.topic = TOPIC;
msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: { tasks: taskDB.items } }]
};

return msg;

