const TOPIC = 'Henkelv2/Shanghai/Logistics/Outbound/State/Staging_Area';
let action = msg.payload;

let staging = global.get('staging_areas') || { areas: [] };
if (!staging.areas || !Array.isArray(staging.areas)) {
    staging.areas = [
        { area_id: 'STAGE-01', items: [] },
        { area_id: 'STAGE-02', items: [] },
        { area_id: 'STAGE-03', items: [] }
    ];
}

let area = staging.areas.find(a => a.area_id === action.area_id);
if (!area) {
    area = { area_id: action.area_id, items: [] };
    staging.areas.push(area);
}

area.items = area.items.filter(i => i.dn_no !== action.dn_no);
area.items.push({
    dn_no: action.dn_no,
    staged_at: Date.now(),
    operator: action.operator || 'System'
});
area.used = area.items.length;

global.set('staging_areas', staging);

msg.topic = TOPIC;
msg.payload = {
    version: '1.0',
    topics: [{ path: TOPIC, type: 'state', value: staging }]
};

return msg;

const TOPIC_DOCKS = 'Henkelv2/Shanghai/Logistics/Outbound/State/Loading_Docks';
